module freq_div(
    input CLK_in, RST,
    output reg CLK_50, CLK_10, CLK_1
);

reg [2:0] count_50;
reg [3:0] count_10;
reg [6:0] count_1;

always @(posedge CLK_in or negedge RST) begin
    if (!RST) begin
        count_50 <= 0;
        count_10 <= 0;
        count_1  <= 0;
        CLK_50 <= 0;
        CLK_10 <= 0;
        CLK_1  <= 0;
    end
    else begin
        // 50MHz clock
        if (count_50 == 4) begin
            count_50 <= 0;
            CLK_50 <= ~CLK_50;
        end
        else begin
            count_50 <= count_50 + 1;
        end

        // 10MHz clock
        if (count_10 == 9) begin
            count_10 <= 0;
            CLK_10 <= ~CLK_10;
        end
        else begin
            count_10 <= count_10 + 1;
        end

        // 1MHz clock
        if (count_1 == 99) begin
            count_1 <= 0;
            CLK_1 <= ~CLK_1;
        end
        else begin
            count_1 <= count_1 + 1;
        end
    end
end

endmodule
